final:
module top_module(X_C, A, B, OP);output reg [31:0] X_C;
input [31:0] A, B;
input [1:0] OP;

always @ (A or B or OP) 
begin
	if (OP == 2'b00) begin
		X_C = A + B;
	end
	else if (OP == 2'b01) begin
		X_C = A & B;
	end
	else if (OP == 2'b10) begin
		X_C = A | B;
	end
	else begin
		X_C = ~A;
	end
end

endmodule
